### Step 8 — Build the Editor Screen (`lib/ui/note_editor_screen.dart`)

```dart
import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import '../models/note.dart';
import '../state/notes_view_model.dart';

class NoteEditorScreen extends StatefulWidget {
  final Note? note;
  const NoteEditorScreen({super.key, this.note});

  @override
  State<NoteEditorScreen> createState() => _NoteEditorScreenState();
}

class _NoteEditorScreenState extends State<NoteEditorScreen> {
  late final TextEditingController _title;
  late final TextEditingController _body;

  @override
  void initState() {
    super.initState();
    _title = TextEditingController(text: widget.note?.title ?? '');
    _body  = TextEditingController(text: widget.note?.body  ?? '');
  }

  @override
  void dispose() {
    _title.dispose();
    _body.dispose();
    super.dispose();
  }

  void _save() {
    final vm = context.read<NotesViewModel>();
    if (_title.text.isEmpty) return;

    if (widget.note == null) {
      vm.addNote(_title.text, _body.text);
    } else {
      vm.updateNote(widget.note!, _title.text, _body.text);
    }
    Navigator.pop(context);
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.note == null ? 'New Note' : 'Edit Note'),
        actions: [
          IconButton(icon: const Icon(Icons.save), onPressed: _save),
        ],
      ),
      body: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          children: [
            TextField(controller: _title, decoration: const InputDecoration(labelText: 'Title')),
            const SizedBox(height: 16),
            Expanded(child: TextField(controller: _body, maxLines: null, expands: true, decoration: const InputDecoration(labelText: 'Body'))),
          ],
        ),
      ),
    );
  }
}
```

