#### Model Solution for Q3 B(b) — Firestore Real-Time Chat

**Step 1 — Firestore Data Model (2 marks)**

```
Collection: chat_rooms
   └── Document: room_123
         ├── name: "Project Discussion"
         ├── createdAt: Timestamp
         └── Subcollection: messages
               ├── Document: msg_001
               │     ├── text: "Hello!"
               │     ├── senderId: "user_alice"
               │     ├── senderName: "Alice"
               │     └── timestamp: Timestamp
               └── Document: msg_002
                     ├── text: "Hi Alice!"
                     ├── senderId: "user_bob"
                     ├── senderName: "Bob"
                     └── timestamp: Timestamp
```

**Step 2 — Firestore CRUD Service (3 marks)**

```dart
import 'package:cloud_firestore/cloud_firestore.dart';

class ChatService {
  final FirebaseFirestore _db = FirebaseFirestore.instance;

  // CREATE — Send a message
  Future<void> sendMessage({
    required String roomId,
    required String text,
    required String senderId,
    required String senderName,
  }) async {
    final messagesRef = _db
        .collection('chat_rooms')
        .doc(roomId)
        .collection('messages');

    await messagesRef.add({
      'text': text,
      'senderId': senderId,
      'senderName': senderName,
      'timestamp': FieldValue.serverTimestamp(),
    });
  }

  // READ — Real-time stream of messages (ordered by time)
  Stream<QuerySnapshot> getMessages(String roomId) {
    return _db
        .collection('chat_rooms')
        .doc(roomId)
        .collection('messages')
        .orderBy('timestamp', descending: false)
        .snapshots();
  }

  // UPDATE — Edit message
  Future<void> editMessage({
    required String roomId,
    required String messageId,
    required String newText,
  }) async {
    await _db
        .collection('chat_rooms')
        .doc(roomId)
        .collection('messages')
        .doc(messageId)
        .update({'text': newText});
  }

  // DELETE — Remove message
  Future<void> deleteMessage({
    required String roomId,
    required String messageId,
  }) async {
    await _db
        .collection('chat_rooms')
        .doc(roomId)
        .collection('messages')
        .doc(messageId)
        .delete();
  }
}
```

**Step 3 — StreamBuilder UI (2 marks)**

```dart
class ChatScreen extends StatelessWidget {
  final String roomId;
  const ChatScreen({super.key, required this.roomId});

  @override
  Widget build(BuildContext context) {
    final chatService = ChatService();

    return Scaffold(
      appBar: AppBar(title: const Text('Chat Room')),
      body: Column(
        children: [
          Expanded(
            child: StreamBuilder<QuerySnapshot>(
              stream: chatService.getMessages(roomId),
              builder: (context, snapshot) {
                if (snapshot.hasError) {
                  return Center(child: Text('Error: ${snapshot.error}'));
                }
                if (snapshot.connectionState == ConnectionState.waiting) {
                  return const Center(child: CircularProgressIndicator());
                }

                final messages = snapshot.data!.docs;

                return ListView.builder(
                  itemCount: messages.length,
                  itemBuilder: (context, index) {
                    final msg = messages[index];
                    return ListTile(
                      title: Text(msg['senderName']),
                      subtitle: Text(msg['text']),
                      trailing: Text(
                        (msg['timestamp'] as Timestamp?)
                                ?.toDate()
                                .toString()
                                .substring(11, 16) ??
                            '',
                      ),
                    );
                  },
                );
              },
            ),
          ),
          // Message input field...
        ],
      ),
    );
  }
}
```

